    TempMaxDate:
    LOAD Max(OrderDate) as MaxDate
    FROM [lib://QVDs/Transform/Sales.qvd] (qvd);
    LET vLastReloadDate = Peek('MaxDate', 0, 'TempMaxDate');
    DROP TABLE TempMaxDate;
